import{_ as n,o,c as i,j as e,a as s,t as l,ai as r,aj as d}from"./chunks/framework.SlQmG7ym.js";const b=JSON.parse('{"title":"Advanced Configuration","description":"","frontmatter":{"title":"Advanced Configuration"},"headers":[],"relativePath":"en/usage/config.md","filePath":"en/usage/config.md"}'),c={name:"en/usage/config.md"},g={id:"frontmatter-title",tabindex:"-1"};function h(a,t,f,m,u,y){return o(),i("div",null,[e("h1",g,[s(l(a.$frontmatter.title)+" ",1),t[0]||(t[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),t[1]||(t[1]=r('<p>You can freely adjust all shock parameters and connection behaviors through the ModConfig visual interface in the game.</p><div class="caution custom-block github-alert"><p class="custom-block-title">Safety Notice</p><p>All baselines for &quot;Minimum Intensity&quot; and &quot;Damage Cap&quot; <strong>depend entirely on the channel limits you manually raise in the Coyote APP</strong>. Therefore, your first line of safety defense is always the limit settings on your phone!</p></div><h2 id="basic-connection-settings" tabindex="-1">Basic Connection Settings <a class="header-anchor" href="#basic-connection-settings" aria-label="Permalink to “Basic Connection Settings”">​</a></h2><ul><li><strong>Port Number</strong>: The port on which the WebSocket server listens. After modifying this, the QR Code needs to be refreshed.</li><li><strong>Bind IP Address</strong>: By default, it binds to the local network address of the network interface capable of accessing the internet. Leave it blank. If you need to use intranet penetration for remote control, you can manually specify it.</li><li><strong>Max Connections</strong>: The number of APPs allowed to connect at the same time (default <code>8</code>).</li><li><strong>Show QR Code</strong> / <strong>Disconnect All</strong>: It is highly recommended to bind handy hotkeys!</li></ul><h2 id="shock-settings-and-parameter-tuning-suggestions" tabindex="-1">Shock Settings and Parameter Tuning Suggestions <a class="header-anchor" href="#shock-settings-and-parameter-tuning-suggestions" aria-label="Permalink to “Shock Settings and Parameter Tuning Suggestions”">​</a></h2><p><img src="'+d+'" alt="Damage and Intensity Relationship Diagram"></p><p>The default parameters (<code>Minimum Intensity=5</code>, <code>Damage Cap=25</code>) belong to a conservative design, perfectly suited for players experiencing this for the first time. You can adjust these values according to the channel intensity limit set in your Coyote App to suit your desired style:</p><ul><li><strong>Minimum Intensity</strong>: Recommended to set at <code>App Channel Limit × 5%</code> (The starting value that you can feel but isn&#39;t stimulating).</li><li><strong>Damage Cap</strong>: Once the Lightning Orb deals damage greater than this value, the current intensity will no longer increase.</li></ul><p><strong>Damage Cap Style Reference Table:</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">Style</th><th style="text-align:left;">Recommended Damage Cap</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Mild</strong></td><td style="text-align:left;"><code>30</code></td><td style="text-align:left;">Suitable for long-term light casual play, hard to reach maximum shock.</td></tr><tr><td style="text-align:left;"><strong>Standard</strong></td><td style="text-align:left;"><code>20~25</code></td><td style="text-align:left;">Default recommendation, balanced damage curve.</td></tr><tr><td style="text-align:left;"><strong>Radical</strong></td><td style="text-align:left;"><code>12~15</code></td><td style="text-align:left;">Thrill-seeking! Even low damage feels very stimulating.</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">Typical Damage Reference (at 25 cap)</p><p></p><ul><li><code>3 Damage</code> yields about <code>50%</code> (Passive without Focus)</li><li><code>8 Damage</code> yields about <code>71%</code> (Evoke without Focus)</li><li><code>11 Damage</code> yields about <code>78%</code> (Evoke with 3 Focus)</li></ul></div><h2 id="waveform-selection" tabindex="-1">Waveform Selection <a class="header-anchor" href="#waveform-selection" aria-label="Permalink to “Waveform Selection”">​</a></h2><p>You can independently configure different Waveforms to be enabled for Channel A and Channel B. We&#39;ve preset several official classic Waveforms:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Waveform Name</th><th style="text-align:left;">Internal ID</th><th style="text-align:left;">Applicable Scenario / Notes</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Breath</strong></td><td style="text-align:left;">Breath</td><td style="text-align:left;">Classic breath, 12 sets cycle</td></tr><tr><td style="text-align:left;"><strong>Tide</strong></td><td style="text-align:left;">Tide</td><td style="text-align:left;">Streamlined for short shocks, rolling and cresting</td></tr><tr><td style="text-align:left;"><strong>Batter</strong></td><td style="text-align:left;">Batter</td><td style="text-align:left;">Streamlined for short shocks, strong impact</td></tr><tr><td style="text-align:left;"><strong>Pinch</strong></td><td style="text-align:left;">Pinch</td><td style="text-align:left;">Streamlined for short shocks, high frequency</td></tr><tr><td style="text-align:left;"><strong>PinchRamp</strong></td><td style="text-align:left;">PinchRamp</td><td style="text-align:left;">Crescendo pinch, suitable for high damage</td></tr><tr><td style="text-align:left;"><strong>Heartbeat</strong></td><td style="text-align:left;">Heartbeat</td><td style="text-align:left;">Simulates heartbeat</td></tr><tr><td style="text-align:left;"><strong>Squeeze</strong></td><td style="text-align:left;">Squeeze</td><td style="text-align:left;">Streamlined for short shocks</td></tr><tr><td style="text-align:left;"><strong>Rhythm</strong></td><td style="text-align:left;">Rhythm</td><td style="text-align:left;">Streamlined for short shocks</td></tr></tbody></table><h3 id="custom-waveform-extension" tabindex="-1">Custom Waveform Extension <a class="header-anchor" href="#custom-waveform-extension" aria-label="Permalink to “Custom Waveform Extension”">​</a></h3><p>If there are no Waveforms that satisfy you, you can expand by adding Waveform files!</p><ol><li>Ensure the Mod has been started at least once, which automatically creates the folders.</li><li>Go to the <code>TazeU/waveforms/</code> folder under the game&#39;s Mod directory.</li><li>Create or place V3 Waveform data in <code>.jsonc</code> format.</li><li><strong>Restart the game</strong> to use your custom Waveforms in the Waveform dropdown menu!</li></ol><div class="tip custom-block github-alert"><p class="custom-block-title">Custom Format</p><p>The JSONC format is very simple. It just needs to contain the <code>name</code> field (the display name in the dropdown menu) and the <code>data</code> array. For specific V3 Waveform hexadecimal encoding details, you can refer to the <a href="https://github.com/DG-LAB-OPENSOURCE/DG-LAB-OPENSOURCE/tree/main/coyote/extra" target="_blank" rel="noreferrer">DG-LAB Official Protocol Documentation</a>.</p></div><p>Based on experience recommendations, custom Waveform length should not exceed 15 sets (i.e., 1.5 seconds). Excessively long Waveforms might lead to a shock experience that isn&#39;t tight enough, especially in battles with frequent triggers.</p>',19))])}const x=n(c,[["render",h]]);export{b as __pageData,x as default};
